    use super::*;
    use helix_provenance::{Confidence, MeasurementMethod, RecordId, ReferenceRange};

    const DAY: i64 = 86_400_000;

    fn rec(measured_at: EpochMillis, confidence: f64) -> ProvRecord {
        ProvRecord {
            id: RecordId::from("r1"),
            source: "Quest".into(),
            measured_at,
            method: MeasurementMethod::LabFeed,
