        let r = rec(9 * DAY, 0.3);
        match assess(now, Some(&r), 365, 0.6).unwrap() {
            AnswerVerdict::Abstain(g) => {
                assert!(matches!(g.reason, AbstentionReason::LowConfidence { .. }))
            }
