    fn abstains_when_no_records() {
        let reg = helix_escalation::builtin_registry_v1();
        let req = AnalyzeRequest {
            concept_code: "2276-4",
            records: &[],
            now: 100 * DAY,
            staleness_window_days: 365,
            confidence_floor: 0.5,
