        let payload = serde_json::json!({
            "concept_code": "2276-4",
            "records": [{
                "id": "r1", "source": "Quest", "measured_at": 1000,
                "method": "lab_feed", "code": "2276-4", "concept": "Ferritin",
                "value": 28.0, "unit": "ng/mL",
